ClearCollect(
    colExistingAssign,
    Filter(
        tbl_mrl_workorder_assign,
        workorder.Id = varSelectedWorkOrder.ID
    )
);

If(
    !IsBlank(ddTeam.Selected.ID),

    // 1. Perform the Assignment
    ForAll(
        Filter(tbl_team_member, team.Id = ddTeam.Selected.ID) As CurrentMember,
        With(
            {
                existingRecord: LookUp(
                    colExistingAssign,
                    technician.Id = CurrentMember.technician.Id
                )
            },
            Patch(
                tbl_mrl_workorder_assign,
                Coalesce(existingRecord, Defaults(tbl_mrl_workorder_assign)),
                {
                    workorder: {
                        Id: varSelectedWorkOrder.ID,
                        Value: varSelectedWorkOrder.workorder_no
                    },
                    technician: {
                        Id: CurrentMember.technician.Id,
                        Value: CurrentMember.technician.Value
                    },
                    team: {
                        Id: CurrentMember.team.Id,
                        Value: CurrentMember.team.Id
                    }
                }
            )
        )
    );

    // 2. LOG THE ACTION FOR THE AUDITOR

   Patch(
    tbl_log,
        Defaults(tbl_log),
        {
            action: "Team Assignment",
            log_category: {
                ID : Blank(),
                Value : "Work Order Log"
            },
            workorder_no_ref: varSelectedWorkOrder.workorder_no,
            performed_by: User().FullName,
            user_email: User().Email,
            user_role: varUserRecord.role.Value,
            // Use PlainText for the description
            details: "Engineer assigned " & ddTeam.Selected.team_name & " to work order.",
            // Force the value to a string
            dept_name: Text(varUserRecord.department.Value),
            location_lat: Location.Latitude,
            location_long: Location.Longitude,
            log_timestamp: Now()
        }
    );

    Notify(
        "Added members from " & ddTeam.Selected.team_name,
        NotificationType.Success
    ),

    Notify("Please Select Team!", NotificationType.Error)
)

Set(previousScreen, WORKORDER_VIEW_ASSIGNED_TECHNICIAN);
Set(varIsNewEntry, false);
Set(checklistWorkOrderId, varSelectedWorkOrder.ID);

Switch(
    varSelectedWorkOrder.maintenance_type.Value,
    "YPM1", Navigate(TASK_CHECKLIST_PM, ScreenTransition.Fade),
    "YCM1", Navigate(TASK_CHECKLIST_CM, ScreenTransition.Fade)
)

// Update Main Work Order Status
Patch(
    tbl_mrl_workorder,
    LookUp(tbl_mrl_workorder, workorder_no = varSelectedWorkOrder.workorder_no),
    {
        status_workorder_dmp: {
            Id: 9,
            Value: "SUB"
        }
    }
);

Patch(
    tbl_mrl_workorder_log,
    Defaults(tbl_mrl_workorder_log),
    {
        workorder_no_ref: varSelectedWorkOrder.workorder_no,
        workorder_status: "SUB",
        user_email: varUserRecord.email,
        user_role: varUserRecord.role.Value,
        user_department: varUserRecord.department.Value,
        location_long: Location.Longitude,
        location_lat: Location.Latitude
    }
);

UpdateContext({isWvatsPopupConfirmSubmit:false});

Notify("Successfully Submit Work Order", NotificationType.Success);
Navigate(WORKORDER_LIST,ScreenTransition.Fade);

Patch(
    tbl_mrl_workorder,
    LookUp(tbl_mrl_workorder, workorder_no = varSelectedWorkOrder.workorder_no),
    {
        status_workorder_dmp: {
            Id: 10,
            Value: "CLS1"
        }
    }
);

Patch(
    tbl_mrl_workorder_log,
    Defaults(tbl_mrl_workorder_log),
    {
        workorder_no_ref: varSelectedWorkOrder.workorder_no,
        workorder_status: "CLS1",
        user_email: varUserRecord.email,
        user_role: varUserRecord.role.Value,
        user_department: varUserRecord.department.Value,
        location_long: Location.Longitude,
        location_lat: Location.Latitude
    }
);

UpdateContext({isWvatPopupConfirmCloseWo:false});

Notify("Successfully Close Work Order", NotificationType.Success);
Navigate(WORKORDER_LIST,ScreenTransition.Fade);

Patch(
    tbl_mrl_workorder_assign,
    LookUp(
        tbl_mrl_workorder_assign,
        workorder.Id = varSelectedWorkOrder.ID && technician.Id = ThisItem.technician.Id
    ),
    {
        leave_remark: {
            Id: Self.Selected.ID,
            Value: Self.Selected.leave_code
        }
    }
)

// 1. Start the loading state
UpdateContext({varIsLoading: true});

// 2. Perform the Refresh
Refresh(tbl_mrl_workorder);

// 3. End the loading state
UpdateContext({varIsLoading: false});

Notify("Data Refreshed", NotificationType.Success)
